import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenerativeAI } from "@google/generative-ai";
import { collegeData } from '../data/collegeData'; 

// 🔑 Your current API Key
const API_KEY = "AIzaSyBA3WcmWZskhy8Wxqkz6aXTkmmgLbNLe38"; 

function ChatBot({ isOpen, onClose, onOpen }) {
  const [messages, setMessages] = useState([
    { text: "👋 DIAGNOSTIC MODE ACTIVATED. Send any message to scan your API key's permissions!", isBot: true }
  ]);
  const [input, setInput] = useState("");
  const [isThinking, setIsThinking] = useState(false);
  const messagesEndRef = useRef(null);

  useEffect(() => {
    if (isOpen) {
       messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }
  }, [messages, isThinking, isOpen]);

  // --- DIAGNOSTIC SCANNER LOGIC ---
  const generateResponse = async (userQuestion) => {
    try {
      if (!API_KEY) return "⚠️ Error: API Key Missing.";
      
      // We are bypassing the SDK entirely and hitting the raw Google API to see the truth
      const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models?key=${API_KEY}`);
      const data = await response.json();
      
      // If Google rejects the key entirely
      if (data.error) {
        return `🚨 GOOGLE API ERROR:\nCode: ${data.error.code}\nStatus: ${data.error.status}\nMessage: ${data.error.message}`;
      }

      // If the key works but has no models attached
      if (!data.models || data.models.length === 0) {
        return `⚠️ The key is valid, but Google says it has access to ZERO models. This usually happens with college/workspace emails.`;
      }

      // Extract the exact names of the models this key is allowed to use
      const availableModels = data.models.map(m => m.name.replace('models/', '')).join(', ');
      
      return `✅ SCAN COMPLETE! Your key works and has access to these exact models:\n\n${availableModels}`;
      
    } catch (error) {
      console.error("Diagnostic Error:", error);
      return `⚠️ Network Fetch Error: ${error.message}`;
    }
  };

  const handleSend = async () => {
    if (!input.trim()) return;
    
    const userMsg = { text: input, isBot: false };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setIsThinking(true);
    
    const aiText = await generateResponse(input);
    
    setIsThinking(false);
    setMessages((prev) => [...prev, { text: aiText, isBot: true }]);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end font-sans">
      
      {!isOpen && (
        <div className="bg-white text-indigo-900 text-xs font-bold px-3 py-1.5 rounded-lg shadow-md mb-2 mr-2 animate-bounce border border-indigo-100">
          💡 Run Diagnostics?
          <div className="absolute right-4 -bottom-1 w-2 h-2 bg-white transform rotate-45 border-r border-b border-indigo-100"></div>
        </div>
      )}

      {isOpen && (
        <div className="bg-white w-80 h-96 rounded-2xl shadow-2xl border border-gray-200 flex flex-col overflow-hidden animate-fade-in-up mb-4">
          <div className="bg-red-600 p-4 flex justify-between items-center text-white shadow-md">
            <div className="flex items-center gap-2">
              <span className="text-xl">🛠️</span>
              <div><h3 className="font-bold text-sm">ScannerBot</h3></div>
            </div>
            <button onClick={onClose} className="hover:bg-red-700 w-8 h-8 rounded-full">✕</button>
          </div>

          <div className="flex-1 p-4 overflow-y-auto bg-gray-50 space-y-3">
            {messages.map((msg, index) => (
              <div key={index} className={`flex ${msg.isBot ? 'justify-start' : 'justify-end'}`}>
                <div className={`max-w-[85%] p-3 rounded-xl text-sm shadow-sm whitespace-pre-wrap ${msg.isBot ? 'bg-white border border-gray-200 text-gray-800' : 'bg-red-600 text-white'}`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {isThinking && <div className="text-xs text-gray-400 p-2">Scanning Google Servers...</div>}
            <div ref={messagesEndRef} />
          </div>

          <div className="p-3 border-t bg-white flex gap-2">
            <input 
              type="text" value={input} onChange={(e) => setInput(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Type anything to scan..." className="flex-1 bg-gray-100 rounded-full px-4 py-2 text-sm outline-none focus:ring-2 focus:ring-red-500"
            />
            <button onClick={handleSend} disabled={isThinking} className="bg-red-600 text-white w-10 h-10 rounded-full flex items-center justify-center">➤</button>
          </div>
        </div>
      )}

      {!isOpen && (
        <button onClick={onOpen} className="w-16 h-16 bg-red-600 text-white rounded-full shadow-lg flex items-center justify-center text-3xl transition-transform hover:scale-110 active:scale-95 border-2 border-white/20">
          🛠️
        </button>
      )}
    </div>
  );
}

export default ChatBot;
